class MessageProcessor:
    def __init__(self):
        self.handlers: Dict[str, Callable] = {}
    
    def register_handler(self, message_type: str, handler: Callable):
        self.handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type}")
    
    def process(self, message_type: str, message_data: Dict[str, Any]) -> Any:
        if message_type not in self.handlers:
            raise ValueError(f"No handler registered for message type: {message_type}")
        
        handler = self.handlers[message_type]
        return handler(message_data)


class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30,
        max_workers: int = 5
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self.max_workers = max_workers
        self.running = False
        
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.processor = MessageProcessor()
        
        logger.info(f"Initialized SQSWorker for queue: {queue_url}")
    
    def register_handler(self, message_type: str, handler: Callable):
        self.processor.register_handler(message_type, handler)
    
    def poll_messages(self) -> List[Dict[str, Any]]:
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            
            messages = response.get('Messages', [])
            if messages:
                logger.info(f"Received {len(messages)} messages from queue")
            
            return messages
        
        except Exception as e:
            logger.error(f"Error polling messages: {str(e)}")
            return []
    
    def parse_message(self, message: Dict[str, Any]) -> Dict[str, Any]:
        try:
            body = message['Body']
            
            try:
                parsed_body = json.loads(body)
            except json.JSONDecodeError:
                parsed_body = {'raw_body': body}
            
            return {
                'message_id': message['MessageId'],
                'receipt_handle': message['ReceiptHandle'],
                'body': parsed_body,
                'attributes': message.get('Attributes', {}),
                'message_attributes': message.get('MessageAttributes', {}),
                'approximate_receive_count': int(message.get('Attributes', {}).get('ApproximateReceiveCount', 0))
            }
        
        except Exception as e:
            logger.error(f"Error parsing message: {str(e)}")
            raise
    
    def process_message(self, message: Dict[str, Any]) -> bool:
        try:
            parsed_message = self.parse_message(message)
            
            logger.info(f"Processing message: {parsed_message['message_id']}")
            
            message_body = parsed_message['body']
            
            if isinstance(message_body, dict):
                message_type = message_body.get('type') or message_body.get('message_type')
                
                if not message_type:
                    message_type = parsed_message['message_attributes'].get('MessageType', {}).get('StringValue')
                
                if not message_type:
                    logger.warning(f"No message type found in message: {parsed_message['message_id']}")
                    message_type = 'default'
                
                message_data = message_body.get('data', message_body)
            else:
                message_type = 'default'
                message_data = message_body
            
            result = self.processor.process(message_type, {
                'data': message_data,
                'metadata': {
                    'message_id': parsed_message['message_id'],
                    'attributes': parsed_message['attributes'],
                    'message_attributes': parsed_message['message_attributes'],
                    'receive_count': parsed_message['approximate_receive_count']
                }
            })
            
            self.delete_message(parsed_message['receipt_handle'])
            
            logger.info(f"Successfully processed message: {parsed_message['message_id']}")
            return True
        
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            logger.error(traceback.format_exc())
            
            parsed_message = self.parse_message(message)
            if parsed_message['approximate_receive_count'] >= 3:
                logger.error(f"Message {parsed_message['message_id']} exceeded max retries, moving to DLQ")
                self.delete_message(parsed_message['receipt_handle'])
            
            return False
    
    def delete_message(self, receipt_handle: str):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.debug("Message deleted from queue")
        
        except Exception as e:
            logger.error(f"Error deleting message: {str(e)}")
    
    def change_message_visibility(self, receipt_handle: str, timeout: int):
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout
            )
        except Exception as e:
            logger.error(f"Error changing message visibility: {str(e)}")
    
    def process_messages_parallel(self, messages: List[Dict[str, Any]]):
        with ThreadPoolExecutor(max_workers=self.max_workers) as executor:
            futures = {executor.submit(self.process_message, msg): msg for msg in messages}
            
            for future in as_completed(futures):
                try:
                    future.result()
                except Exception as e:
                    logger.error(f"Unhandled exception in message processing: {str(e)}")
    
    def start(self, parallel: bool = True):
        self.running = True
        logger.info("Starting SQS worker...")
        
        while self.running:
            try:
                messages = self.poll_messages()
                
                if messages:
                    if parallel:
                        self.process_messages_parallel(messages)
                    else:
                        for message in messages:
                            self.process_message(message)
                else:
                    logger.debug("No messages received, continuing to poll...")
                
            except KeyboardInterrupt:
                logger.info("Received shutdown signal")
                self.stop()
                break
            
            except Exception as e:
                logger.error(f"Unexpected error in worker loop: {str(e)}")
                logger.error(traceback.format_exc())
                time.sleep(5)
    
    def stop(self):
        logger.info("Stopping SQS worker...")
        self.running = False


